import{_ as e,o as t,c as i,a2 as n}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"Chapter 1: What Is a Coding Agent?","description":"An introduction to AI coding agents, the current landscape, and the architectural patterns that power them.","frontmatter":{"title":"Chapter 1: What Is a Coding Agent?","description":"An introduction to AI coding agents, the current landscape, and the architectural patterns that power them."},"headers":[],"relativePath":"learn/linear/01-what-is-a-coding-agent/index.md","filePath":"learn/linear/01-what-is-a-coding-agent/index.md"}'),o={name:"learn/linear/01-what-is-a-coding-agent/index.md"};function l(r,a,s,h,d,c){return t(),i("div",null,[...a[0]||(a[0]=[n('<h1 id="what-is-a-coding-agent" tabindex="-1">What Is a Coding Agent? <a class="header-anchor" href="#what-is-a-coding-agent" aria-label="Permalink to &quot;What Is a Coding Agent?&quot;">​</a></h1><p>The emergence of AI coding agents represents a fundamental shift in how software is written. Unlike simple code completion tools or chatbots that respond to isolated questions, coding agents operate autonomously within development environments — reading files, executing commands, running tests, and iterating on solutions. This chapter establishes the foundational understanding of what coding agents are, how they differ from earlier AI-assisted development tools, and why they matter.</p><p>We begin by surveying the current landscape of production coding agents including Claude Code, OpenCode, Pi, and Codex. By studying how each system approaches the problem of autonomous code generation and manipulation, you will develop an intuition for the common architectural patterns that underlie all of them. This comparative analysis reveals that despite surface-level differences, these tools share a remarkably consistent core design.</p><p>By the end of this chapter, you will have a clear mental model of what a coding agent is, how the major players differ, and what we will build throughout the rest of this tutorial track. You will also understand why Rust is our language of choice and what the final system will look like.</p><h2 id="learning-objectives" tabindex="-1">Learning Objectives <a class="header-anchor" href="#learning-objectives" aria-label="Permalink to &quot;Learning Objectives&quot;">​</a></h2><ul><li>Define what a coding agent is and how it differs from chatbots and code completion tools</li><li>Identify the major production coding agents and their distinguishing characteristics</li><li>Recognize the common architectural patterns shared across all coding agents</li><li>Understand the motivation for building a custom coding agent from scratch</li><li>Articulate the high-level architecture of the system we will build in this track</li></ul><h2 id="subchapters" tabindex="-1">Subchapters <a class="header-anchor" href="#subchapters" aria-label="Permalink to &quot;Subchapters&quot;">​</a></h2><ol><li><a href="/linear/01-what-is-a-coding-agent/01-the-ai-coding-revolution.html">The AI Coding Revolution</a></li><li><a href="/linear/01-what-is-a-coding-agent/02-defining-coding-agents.html">Defining Coding Agents</a></li><li><a href="/linear/01-what-is-a-coding-agent/03-history-and-evolution.html">History and Evolution</a></li><li><a href="/linear/01-what-is-a-coding-agent/04-the-landscape-today.html">The Landscape Today</a></li><li><a href="/linear/01-what-is-a-coding-agent/05-claude-code-analysis.html">Claude Code Analysis</a></li><li><a href="/linear/01-what-is-a-coding-agent/06-opencode-analysis.html">OpenCode Analysis</a></li><li><a href="/linear/01-what-is-a-coding-agent/07-pi-agent-analysis.html">Pi Agent Analysis</a></li><li><a href="/linear/01-what-is-a-coding-agent/08-codex-analysis.html">Codex Analysis</a></li><li><a href="/linear/01-what-is-a-coding-agent/09-common-architecture-patterns.html">Common Architecture Patterns</a></li><li><a href="/linear/01-what-is-a-coding-agent/10-agentic-vs-chatbot.html">Agentic vs Chatbot</a></li><li><a href="/linear/01-what-is-a-coding-agent/11-why-build-your-own.html">Why Build Your Own</a></li><li><a href="/linear/01-what-is-a-coding-agent/12-choosing-a-language.html">Choosing a Language</a></li><li><a href="/linear/01-what-is-a-coding-agent/13-what-well-build.html">What We&#39;ll Build</a></li><li><a href="/linear/01-what-is-a-coding-agent/14-summary.html">Summary</a></li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>None — this is the starting point</li></ul>',10)])])}const m=e(o,[["render",l]]);export{u as __pageData,m as default};
